<?php\n\nnamespace App\\Helpers;\n\nuse Illuminate\\Support\\Str;\n\nclass SkuGenerator\n{\n    /**\n     * Generates a unique Stock Keeping Unit (SKU).\n     * In a real-world application, this might involve checking against existing SKUs\n     * in the database to ensure uniqueness, or using a more sophisticated algorithm.\n     *\n     * @param string|null $productName Optional product name to base the SKU on.\n     * @return string\n     */\n    public static function generateSku(?string $productName = null): string\n    {\n        $base = '';\n        if ($productName) {\n            // Take first few letters of product name, capitalize, remove spaces/special chars\n            $base = Str::upper(\n                preg_replace('/[^A-Z]/', '', Str::ascii(Str::substr($productName, 0, 5)))\n            );\n        }\n\n        // Append a unique identifier (e.g., timestamp + random string)\n        $uniquePart = date('YmdHis') . substr(str_shuffle('0123456789ABCDEFGHIJKLMNOPQRSTUVWXYZ'), 0, 4);\n        \n        // Ensure SKU is within a reasonable length and is unique\n        // For true uniqueness guarantee, database check is required\n        $sku = $base . '-' . $uniquePart;\n\n        // Truncate if too long, though unlikely with this generation method\n        return Str::substr($sku, 0, 30); \n    }\n\n    /**\n     * Placeholder for barcode/QR code generation logic.\n     * This typically involves external libraries (e.g., `picqer/php-barcode-generator`)\n     * or dedicated services.\n     *\n     * @param string $sku The SKU to generate a barcode for.\n     * @return string Path to the generated image or base64 encoded image.\n     */\n    public static function generateBarcodeImage(string $sku): string\n    {\n        // Example: return '/path/to/barcode_images/' . $sku . '.png';\n        // Or use a library to generate and return base64:\n        // $generator = new \Picqer\Barcode\BarcodeGeneratorPNG();\n        // return 'data:image/png;base64,' . base64_encode($generator->getBarcode($sku, $generator::TYPE_CODE_128));\n        \n        return 'placeholder_barcode_for_' . $sku . '.png'; // Placeholder\n    }\n\n    /**\n     * Placeholder for QR code generation logic.\n     * Similar to barcode generation, requires external libraries.\n     *\n     * @param string $sku The SKU to generate a QR code for.\n     * @return string Path to the generated image or base64 encoded image.\n     */\n    public static function generateQrCodeImage(string $sku): string\n    {\n        // Example: return '/path/to/qr_images/' . $sku . '.png';\n        // Or use a library (e.g., `chillerlan/php-qrcode`)\n        // $qrcode = new QrCode($sku);\n        // return 'data:image/png;base64,' . base64_encode($qrcode->writeString());\n\n        return 'placeholder_qr_for_' . $sku . '.png'; // Placeholder\n    }\n}\n